// En tu componente CountdownTimer.js
import React, { useState, useEffect, useRef } from 'react';

const CountdownTimer = ({ onComplete }) => {
  const [timeLeft, setTimeLeft] = useState({ minutes: 0, seconds: 20 }); // 20 seg para prueba
  const completedRef = useRef(false);

  useEffect(() => {
    const timer = setInterval(() => {
      setTimeLeft(prev => {
        const totalSeconds = prev.minutes * 60 + prev.seconds;
        
        if (totalSeconds <= 0) {
          clearInterval(timer);
          // SOLO llamar onComplete una vez
          if (!completedRef.current) {
            completedRef.current = true;
            onComplete();
          }
          return prev;
        }
        
        const newTotalSeconds = totalSeconds - 1;
        return {
          minutes: Math.floor(newTotalSeconds / 60),
          seconds: newTotalSeconds % 60
        };
      });
    }, 1000);

    return () => clearInterval(timer);
  }, [onComplete]); // Solo depende de onComplete

  return (
    <div className="countdown-timer">
      <span>{String(timeLeft.minutes).padStart(2, '0')}:</span>
      <span>{String(timeLeft.seconds).padStart(2, '0')}</span>
    </div>
  );
};

export default CountdownTimer;
